import React from "react";
import {
  VerticalTimeline,
  VerticalTimelineElement,
} from "react-vertical-timeline-component";
import "react-vertical-timeline-component/style.min.css";

import { FaBriefcase, FaUniversity, FaCloud } from "react-icons/fa";

// Estilos comunes agrupados por tipo de icono
const iconStylesByType = {
  briefcase: {
    iconBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    contentBgGradient: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
    arrowBorderColor: "#764ba2",
    fontSize: "1rem",
  },
  university: {
    iconBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    contentBgGradient: "linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)",
    arrowBorderColor: "#3b82f6",
    fontSize: "0.85rem",
  },
  cloud: {
    iconBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    contentBgGradient: "linear-gradient(135deg, #0072c6 0%, #00a1f1 100%)",
    arrowBorderColor: "#00a1f1",
    fontSize: "1rem",
  },
};

// Mapea el tipo de icono a un string para buscar estilos
function getIconType(icon) {
  if (!icon) return null;
  const typeName = icon.type.displayName || icon.type.name || "";
  if (typeName === "FaBriefcase") return "briefcase";
  if (typeName === "FaUniversity") return "university";
  if (typeName === "FaCloud") return "cloud";
  return null;
}

const experienceData = [
  {
    title: "Senior Product Manager",
    company: "EY",
    date: "2022-Present",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "J.P. Morgan",
    date: "2021-2022",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Manager",
    company: "ExxonMobil",
    date: "2014-2021",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Product Owner",
    company: "ExxonMobil",
    date: "2013-2014",
    icon: <FaBriefcase />,
  },
  {
    title: "Senior Scrum Master",
    company: "ExxonMobil",
    date: "2008-2013",
    icon: <FaBriefcase />,
  },
  {
    title: "Supervisor",
    company: "IBM",
    date: "2001-2008",
    icon: <FaBriefcase />,
  },
  {
    title: "Master of Systems Engineering",
    company: "Universidad Tecnologica Nacional (UTN)",
    date: "2001-2006",
    icon: <FaUniversity />,
  },
  {
    title: "Microsoft Certified: Azure Fundamentals",
    company: "Azure",
    date: "2021",
    icon: <FaCloud />,
  },
  {
    title: "PMI Agile Certified Practitioner (PMIACP)",
    company: "PMI",
    date: "2019",
    icon: <FaUniversity />,
  },
  {
    title: "Certified SAFe® 6 Product Owner/Product Manager",
    company: "Scaled Agile",
    date: "2024",
    icon: <FaUniversity />,
  },
  {
    title: "Certified Scrum Product Owner (CSPO)",
    company: "Scrum Alliance",
    date: "2022",
    icon: <FaUniversity />,
  },
];

export default function ExperienceTimeline() {
  // Ordenar experiencia por año inicio descendente
  const sortedData = experienceData.sort((a, b) => {
    const getYear = (str) => {
      const match = str.match(/\d{4}/);
      return match ? parseInt(match[0]) : 0;
    };
    return getYear(b.date) - getYear(a.date);
  });

  return (
    <VerticalTimeline>
      {sortedData.map((exp, idx) => {
        const sideLeft = idx % 2 === 0;
        const iconType = getIconType(exp.icon);
        const styles = iconStylesByType[iconType] || {
          iconBgGradient: "#888",
          contentBgGradient: "#aaa",
          arrowBorderColor: "#aaa",
          fontSize: "1rem",
        };

        const dateStyle = {
          position: "absolute",
          top: 12,
          width: 80,
          fontWeight: "bold",
          color: "white",
          textShadow: "0 0 5px rgba(0,0,0,0.7)",
          fontSize: "0.9rem",
          zIndex: 10,
          textAlign: sideLeft ? "right" : "left",
          left: sideLeft ? -90 : "auto",
          right: !sideLeft ? -90 : "auto",
        };

        return (
          <VerticalTimelineElement
            key={idx}
            date={<span style={dateStyle}>{exp.date}</span>}
            iconStyle={{
              background: styles.iconBgGradient,
              color: "#fff",
              boxShadow: "0 0 10px rgba(0,0,0,0.2)",
            }}
            contentStyle={{
              background: styles.contentBgGradient,
              color: "#fff",
              boxShadow: "0 4px 15px rgba(0,0,0,0.15)",
              fontSize: styles.fontSize,
              width: "auto",
              maxWidth: "280px",
            }}
            contentArrowStyle={{
              borderRight: `7px solid ${styles.arrowBorderColor}`,
            }}
            style={{ marginBottom: "10px", marginTop: "10px" }}
            icon={exp.icon}
          >
            <h3 style={{ margin: "0 0 4px 0" }}>{exp.title}</h3>
            <h4 style={{ margin: 0 }}>{exp.company}</h4>
          </VerticalTimelineElement>
        );
      })}
    </VerticalTimeline>
  );
}
